        P_ID_CATEGORIA IN FIDE_SERVICIO_TB.ID_CATEGORIA%TYPE,
        P_ID_ESTADO IN FIDE_SERVICIO_TB.ID_ESTADO%TYPE
    );
    
    PROCEDURE FIDE_SERVICIO_EDITAR_SP(
        P_ID_SERVICIO IN FIDE_SERVICIO_TB.ID_SERVICIO%TYPE,
        P_NOMBRE_SERVICIO IN FIDE_SERVICIO_TB.NOMBRE_SERVICIO%TYPE,
        P_DESCRIPCION IN FIDE_SERVICIO_TB.DESCRIPCION%TYPE,
        P_VALOR_ESTIMADO IN FIDE_SERVICIO_TB.VALOR_ESTIMADO%TYPE,
        P_STOCK IN FIDE_SERVICIO_TB.STOCK%TYPE,
        P_ID_CATEGORIA IN FIDE_SERVICIO_TB.ID_CATEGORIA%TYPE,
        P_ID_ESTADO IN FIDE_SERVICIO_TB.ID_ESTADO%TYPE
    );
    
    PROCEDURE FIDE_SERVICIO_ELIMINAR_SP(
        P_ID_SERVICIO IN FIDE_SERVICIO_TB.ID_SERVICIO%TYPE
    );
    
    -- =============================================
    -- PROCEDIMIENTOS PARA FIDE_TIPO_AHORRO_TB
    -- =============================================
    PROCEDURE FIDE_TIPO_AHORRO_INSERTAR_SP(
        P_NOMBRE IN FIDE_TIPO_AHORRO_TB.NOMBRE%TYPE,
        P_DESCRIPCION IN FIDE_TIPO_AHORRO_TB.DESCRIPCION%TYPE,
        P_ID_ESTADO IN FIDE_TIPO_AHORRO_TB.ID_ESTADO%TYPE
    );
    
    PROCEDURE FIDE_TIPO_AHORRO_EDITAR_SP(
        P_ID_TIPO_AHORRO IN FIDE_TIPO_AHORRO_TB.ID_TIPO_AHORRO%TYPE,
        P_NOMBRE IN FIDE_TIPO_AHORRO_TB.NOMBRE%TYPE,
        P_DESCRIPCION IN FIDE_TIPO_AHORRO_TB.DESCRIPCION%TYPE,
        P_ID_ESTADO IN FIDE_TIPO_AHORRO_TB.ID_ESTADO%TYPE
    );
    
    PROCEDURE FIDE_TIPO_AHORRO_ELIMINAR_SP(
        P_ID_TIPO_AHORRO IN FIDE_TIPO_AHORRO_TB.ID_TIPO_AHORRO%TYPE
    );
    
    -- =============================================
    -- PROCEDIMIENTOS PARA FIDE_TIPO_REPORTE_TB
    -- =============================================
    PROCEDURE FIDE_TIPO_REPORTE_INSERTAR_SP(
        P_NOMBRE IN FIDE_TIPO_REPORTE_TB.NOMBRE%TYPE,
        P_ID_ESTADO IN FIDE_TIPO_REPORTE_TB.ID_ESTADO%TYPE
    );
    
    PROCEDURE FIDE_TIPO_REPORTE_EDITAR_SP(
        P_ID_TIPO_REPORTE IN FIDE_TIPO_REPORTE_TB.ID_TIPO_REPORTE%TYPE,
        P_NOMBRE IN FIDE_TIPO_REPORTE_TB.NOMBRE%TYPE,
        P_ID_ESTADO IN FIDE_TIPO_REPORTE_TB.ID_ESTADO%TYPE
    );
    
    PROCEDURE FIDE_TIPO_REPORTE_ELIMINAR_SP(
        P_ID_TIPO_REPORTE IN FIDE_TIPO_REPORTE_TB.ID_TIPO_REPORTE%TYPE
    );
    
    -- =============================================
    -- PROCEDIMIENTOS PARA FIDE_TIPO_TRANSACCION_TB
    -- =============================================
    PROCEDURE FIDE_TIPO_TRANSACCION_INSERTAR_SP(
        P_NOMBRE IN FIDE_TIPO_TRANSACCION_TB.NOMBRE%TYPE,
        P_DESCRIPCION IN FIDE_TIPO_TRANSACCION_TB.DESCRIPCION%TYPE,
        P_ID_ESTADO IN FIDE_TIPO_TRANSACCION_TB.ID_ESTADO%TYPE
    );
    
    PROCEDURE FIDE_TIPO_TRANSACCION_EDITAR_SP(
        P_ID_TIPO_TRANSACCION IN FIDE_TIPO_TRANSACCION_TB.ID_TIPO_TRANSACCION%TYPE,
        P_NOMBRE IN FIDE_TIPO_TRANSACCION_TB.NOMBRE%TYPE,
        P_DESCRIPCION IN FIDE_TIPO_TRANSACCION_TB.DESCRIPCION%TYPE,
        P_ID_ESTADO IN FIDE_TIPO_TRANSACCION_TB.ID_ESTADO%TYPE
    );
    
    PROCEDURE FIDE_TIPO_TRANSACCION_ELIMINAR_SP(
        P_ID_TIPO_TRANSACCION IN FIDE_TIPO_TRANSACCION_TB.ID_TIPO_TRANSACCION%TYPE
    );
    
    -- =============================================
    -- PROCEDIMIENTOS PARA FIDE_TRANSACCION_TB
    -- =============================================
    PROCEDURE FIDE_TRANSACCION_INSERTAR_SP(
        P_FECHA_TRANSACCION IN FIDE_TRANSACCION_TB.FECHA_TRANSACCION%TYPE,
        P_ID_TIPO_TRANSACCION IN FIDE_TRANSACCION_TB.ID_TIPO_TRANSACCION%TYPE,
        P_MONTO_TOTAL IN FIDE_TRANSACCION_TB.MONTO_TOTAL%TYPE,
        P_ID_USUARIO IN FIDE_TRANSACCION_TB.ID_USUARIO%TYPE,
        P_ID_ESTADO IN FIDE_TRANSACCION_TB.ID_ESTADO%TYPE
    );
    
    PROCEDURE FIDE_TRANSACCION_EDITAR_SP(
        P_ID_TRANSACCION IN FIDE_TRANSACCION_TB.ID_TRANSACCION%TYPE,
        P_FECHA_TRANSACCION IN FIDE_TRANSACCION_TB.FECHA_TRANSACCION%TYPE,
        P_ID_TIPO_TRANSACCION IN FIDE_TRANSACCION_TB.ID_TIPO_TRANSACCION%TYPE,
        P_MONTO_TOTAL IN FIDE_TRANSACCION_TB.MONTO_TOTAL%TYPE,
        P_ID_USUARIO IN FIDE_TRANSACCION_TB.ID_USUARIO%TYPE,
        P_ID_ESTADO IN FIDE_TRANSACCION_TB.ID_ESTADO%TYPE
    );
    
    PROCEDURE FIDE_TRANSACCION_ELIMINAR_SP(
        P_ID_TRANSACCION IN FIDE_TRANSACCION_TB.ID_TRANSACCION%TYPE
    );
    
    -- =============================================
    -- PROCEDIMIENTOS PARA FIDE_USUARIOS_ROLES_TB
    -- =============================================
    PROCEDURE FIDE_USUARIOS_ROLES_INSERTAR_SP(
        P_ID_USUARIO IN FIDE_USUARIOS_ROLES_TB.ID_USUARIO%TYPE,
        P_ID_ROL IN FIDE_USUARIOS_ROLES_TB.ID_ROL%TYPE
    );
    
    PROCEDURE FIDE_USUARIOS_ROLES_EDITAR_SP(
        P_ID_USUARIO_OLD IN FIDE_USUARIOS_ROLES_TB.ID_USUARIO%TYPE,
        P_ID_ROL_OLD IN FIDE_USUARIOS_ROLES_TB.ID_ROL%TYPE,
        P_ID_USUARIO_NEW IN FIDE_USUARIOS_ROLES_TB.ID_USUARIO%TYPE,
        P_ID_ROL_NEW IN FIDE_USUARIOS_ROLES_TB.ID_ROL%TYPE
    );
    
    PROCEDURE FIDE_USUARIOS_ROLES_ELIMINAR_SP(
        P_ID_USUARIO IN FIDE_USUARIOS_ROLES_TB.ID_USUARIO%TYPE,
        P_ID_ROL IN FIDE_USUARIOS_ROLES_TB.ID_ROL%TYPE
    );
    
    -- =============================================
    -- PROCEDIMIENTOS PARA FIDE_DETALLE_TRANSACCION_TB
    -- =============================================
    PROCEDURE FIDE_DETALLE_TRANSACCION_INSERTAR_SP(
        P_ID_TRANSACCION IN FIDE_DETALLE_TRANSACCION_TB.ID_TRANSACCION%TYPE,
        P_CONCEPTO IN FIDE_DETALLE_TRANSACCION_TB.CONCEPTO%TYPE,
        P_SUB_TOTAL IN FIDE_DETALLE_TRANSACCION_TB.SUB_TOTAL%TYPE
    );
    
    PROCEDURE FIDE_DETALLE_TRANSACCION_EDITAR_SP(
        P_ID_DETALLE IN FIDE_DETALLE_TRANSACCION_TB.ID_DETALLE%TYPE,
        P_ID_TRANSACCION IN FIDE_DETALLE_TRANSACCION_TB.ID_TRANSACCION%TYPE,
        P_CONCEPTO IN FIDE_DETALLE_TRANSACCION_TB.CONCEPTO%TYPE,
        P_SUB_TOTAL IN FIDE_DETALLE_TRANSACCION_TB.SUB_TOTAL%TYPE
    );
    
    PROCEDURE FIDE_DETALLE_TRANSACCION_ELIMINAR_SP(
        P_ID_DETALLE IN FIDE_DETALLE_TRANSACCION_TB.ID_DETALLE%TYPE
    );

END ASEFIDE_PKG;
/


--------------------------------------------------------------------------------------
---------------------------------- BODY DEL PAQUETE ----------------------------------
--------------------------------------------------------------------------------------

CREATE OR REPLACE PACKAGE BODY ASEFIDE_PKG AS

    -- =============================================
    -- IMPLEMENTACIÓN FUNCIONES
    -- =============================================

    -- 1. Función Listar Usuarios
    FUNCTION FIDE_LISTAR_USUARIOS_FN RETURN NUMBER IS
        CURSOR CURSOR_USUARIOS IS
            SELECT ID_USUARIO, 
                   NOMBRE, 
                   APELLIDO_PATERNO, 
                   APELLIDO_MATERNO
            FROM FIDE_USUARIO_TB;
        V_CONTADOR NUMBER := 0;
    BEGIN
        FOR USUARIO IN CURSOR_USUARIOS
        LOOP
            V_CONTADOR := V_CONTADOR + 1;
            DBMS_OUTPUT.PUT_LINE(
                'ID: ' || USUARIO.ID_USUARIO || 
                ' - NOMBRE: ' || USUARIO.NOMBRE || ' ' || 
                USUARIO.APELLIDO_PATERNO || ' ' || 
                USUARIO.APELLIDO_MATERNO
            );
        END LOOP;
        RETURN V_CONTADOR;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            DBMS_OUTPUT.PUT_LINE('NO SE ENCONTRARON DATOS');
            RETURN 0;
        WHEN TOO_MANY_ROWS THEN
            DBMS_OUTPUT.PUT_LINE('DATOS DUPLICADOS');
            RETURN -1;
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
            RETURN -1;
    END FIDE_LISTAR_USUARIOS_FN;

    -- 2. Función Suma Total De Montos De Ahorro Del Sistema
    FUNCTION FIDE_SUMA_TOTAL_AHORROS_FN RETURN NUMBER IS
        CURSOR CURSOR_AHORROS IS
            SELECT SALDO_ACTUAL
            FROM FIDE_CUENTAS_AHORRO_TB;
        V_SUMA_TOTAL NUMBER := 0;
    BEGIN
        FOR AHORRO IN CURSOR_AHORROS
        LOOP
            V_SUMA_TOTAL := V_SUMA_TOTAL + AHORRO.SALDO_ACTUAL;
        END LOOP;
        DBMS_OUTPUT.PUT_LINE('TOTAL DE AHORROS DEL SISTEMA: ' || V_SUMA_TOTAL);
        RETURN V_SUMA_TOTAL;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            DBMS_OUTPUT.PUT_LINE('NO SE ENCONTRARON DATOS');
            RETURN 0;
        WHEN TOO_MANY_ROWS THEN
            DBMS_OUTPUT.PUT_LINE('DATOS DUPLICADOS');
            RETURN -1;
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
            RETURN -1;
    END FIDE_SUMA_TOTAL_AHORROS_FN;

    -- 3. Función Ordenar Usuarios Alfabéticamente.
    FUNCTION FIDE_ORDENAR_USUARIOS_ALFABETICO_FN 
RETURN SYS_REFCURSOR 
IS
    V_CURSOR SYS_REFCURSOR;
BEGIN
    OPEN V_CURSOR FOR
        SELECT 
            U.ID_USUARIO,
            U.NOMBRE || ' ' || U.APELLIDO_PATERNO || ' ' || U.APELLIDO_MATERNO AS NOMBRE_COMPLETO,
            U.NOMBRE_USUARIO,
            T.NUMERO_TELEFONO,
            C.CORREO_ELECTRONICO,
            D.DISTRITO,
            DA.APORTE_MENSUAL,
            E.NOMBRE AS ESTADO
        FROM FIDE_USUARIO_TB U
        LEFT JOIN FIDE_NUMERO_TELEFONO_TB T ON U.ID_NUMERO = T.ID_NUMERO
        LEFT JOIN FIDE_CORREO_ELECTRONICO_TB C ON U.ID_CORREO = C.ID_CORREO
        LEFT JOIN FIDE_DIRECCION_TB D ON U.ID_DIRECCION = D.ID_DIRECCION
        LEFT JOIN FIDE_DATOS_ASOCIADOS_TB DA ON U.ID_DATOS_ASOCIADOS = DA.ID_DATOS_ASOCIADOS
        LEFT JOIN FIDE_ESTADO_TB E ON U.ID_ESTADO = E.ID_ESTADO
        ORDER BY 
            U.NOMBRE ASC, 
            U.APELLIDO_PATERNO ASC, 
            U.APELLIDO_MATERNO ASC;

    RETURN V_CURSOR;

EXCEPTION
    WHEN OTHERS THEN
        RETURN NULL;
END FIDE_ORDENAR_USUARIOS_ALFABETICO_FN;

    -- 4. Función Ordenar Usuarios Por Fecha De Afiliación
    FUNCTION FIDE_ORDENAR_USUARIOS_FECHA_FN RETURN NUMBER IS
        CURSOR CURSOR_FECHA IS
            SELECT U.NOMBRE, 
                   U.APELLIDO_PATERNO, 
                   D.FECHA_AFILIACION
            FROM FIDE_USUARIO_TB U
            JOIN FIDE_DATOS_ASOCIADOS_TB D 
            ON U.ID_DATOS_ASOCIADOS = D.ID_DATOS_ASOCIADOS
            ORDER BY D.FECHA_AFILIACION ASC;
        V_CONTADOR NUMBER := 0;
    BEGIN
        FOR USUARIO IN CURSOR_FECHA
        LOOP
            V_CONTADOR := V_CONTADOR + 1;
            DBMS_OUTPUT.PUT_LINE(
                'USUARIO: ' || USUARIO.NOMBRE || ' ' || 
                USUARIO.APELLIDO_PATERNO || 
                ' - FECHA AFILIACION: ' || USUARIO.FECHA_AFILIACION
            );
        END LOOP;
        RETURN V_CONTADOR;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            DBMS_OUTPUT.PUT_LINE('NO SE ENCONTRARON DATOS');
            RETURN 0;
        WHEN TOO_MANY_ROWS THEN
            DBMS_OUTPUT.PUT_LINE('DATOS DUPLICADOS');
            RETURN -1;
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
            RETURN -1;
    END FIDE_ORDENAR_USUARIOS_FECHA_FN;

    -- 5. Función Top 10 Usuarios Con Más Ahorros
    FUNCTION FIDE_TOP10_MAS_AHORROS_FN RETURN NUMBER IS
        CURSOR CURSOR_MAS_AHORROS IS
            SELECT * FROM (
                SELECT U.NOMBRE, 
                       U.APELLIDO_PATERNO, 
                       SUM(A.SALDO_ACTUAL) AS TOTAL_AHORRO
                FROM FIDE_USUARIO_TB U
                JOIN FIDE_CUENTAS_AHORRO_TB A 
                ON U.ID_USUARIO = A.ID_USUARIO
                GROUP BY U.NOMBRE, 
                         U.APELLIDO_PATERNO
                ORDER BY TOTAL_AHORRO DESC
            )
            WHERE ROWNUM <= 10;
        V_CONTADOR NUMBER := 0;
    BEGIN
        FOR USUARIO IN CURSOR_MAS_AHORROS
        LOOP
            V_CONTADOR := V_CONTADOR + 1;
            DBMS_OUTPUT.PUT_LINE(
                'USUARIO: ' || USUARIO.NOMBRE || ' ' || 
                USUARIO.APELLIDO_PATERNO || 
                ' - TOTAL AHORROS: ' || USUARIO.TOTAL_AHORRO
            );
        END LOOP;
        RETURN V_CONTADOR;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            DBMS_OUTPUT.PUT_LINE('NO SE ENCONTRARON DATOS');
            RETURN 0;
        WHEN TOO_MANY_ROWS THEN
            DBMS_OUTPUT.PUT_LINE('DATOS DUPLICADOS');
            RETURN -1;
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
            RETURN -1;
    END FIDE_TOP10_MAS_AHORROS_FN;
    
-- 6. Función Top 10 Usuarios Con Menos Ahorros
    FUNCTION FIDE_TOP10_MENOS_AHORROS_FN RETURN NUMBER IS
        CURSOR CURSOR_MENOS_AHORROS IS
            SELECT * FROM (
                SELECT U.NOMBRE, 
                       U.APELLIDO_PATERNO, 
                       NVL(SUM(A.SALDO_ACTUAL), 0) AS TOTAL_AHORRO
                FROM FIDE_USUARIO_TB U
                LEFT JOIN FIDE_CUENTAS_AHORRO_TB A 
                ON U.ID_USUARIO = A.ID_USUARIO
                GROUP BY U.NOMBRE, 
                         U.APELLIDO_PATERNO
                ORDER BY TOTAL_AHORRO ASC
            )
            WHERE ROWNUM <= 10;
        V_CONTADOR NUMBER := 0;
    BEGIN
        FOR USUARIO IN CURSOR_MENOS_AHORROS
        LOOP
            V_CONTADOR := V_CONTADOR + 1;
            DBMS_OUTPUT.PUT_LINE(
                'USUARIO: ' || USUARIO.NOMBRE || ' ' || 
                USUARIO.APELLIDO_PATERNO || 
                ' - TOTAL AHORROS: ' || USUARIO.TOTAL_AHORRO
            );
        END LOOP;
        DBMS_OUTPUT.PUT_LINE('TOTAL USUARIOS LISTADOS: ' || V_CONTADOR);
        RETURN V_CONTADOR;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            DBMS_OUTPUT.PUT_LINE('NO SE ENCONTRARON DATOS');
            RETURN 0;
        WHEN TOO_MANY_ROWS THEN
            DBMS_OUTPUT.PUT_LINE('DATOS DUPLICADOS');
            RETURN -1;
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
            RETURN -1;
    END FIDE_TOP10_MENOS_AHORROS_FN;
    
    -- 7. Función Buscar Usuarios Por Nombre
    FUNCTION FIDE_BUSCAR_USUARIOS_NOMBRE_FN(
        P_NOMBRE_BUSCAR VARCHAR2
    ) RETURN NUMBER IS
        CURSOR CURSOR_BUSQUEDA IS
            SELECT ID_USUARIO,
                   NOMBRE,
                   APELLIDO_PATERNO,
                   APELLIDO_MATERNO,
                   NOMBRE_USUARIO
            FROM FIDE_USUARIO_TB
            WHERE UPPER(NOMBRE) LIKE '%' || UPPER(P_NOMBRE_BUSCAR) || '%'
               OR UPPER(APELLIDO_PATERNO) LIKE '%' || UPPER(P_NOMBRE_BUSCAR) || '%'
               OR UPPER(APELLIDO_MATERNO) LIKE '%' || UPPER(P_NOMBRE_BUSCAR) || '%'
            ORDER BY NOMBRE, APELLIDO_PATERNO;
        V_CONTADOR NUMBER := 0;
    BEGIN
        FOR USUARIO IN CURSOR_BUSQUEDA
        LOOP
            V_CONTADOR := V_CONTADOR + 1;
            DBMS_OUTPUT.PUT_LINE(
                'ID: ' || USUARIO.ID_USUARIO ||
                ' - NOMBRE: ' || USUARIO.NOMBRE || ' ' || 
                USUARIO.APELLIDO_PATERNO || ' ' || 
                NVL(USUARIO.APELLIDO_MATERNO, '') ||
                ' - USER: ' || USUARIO.NOMBRE_USUARIO
            );
        END LOOP;
        DBMS_OUTPUT.PUT_LINE('TOTAL USUARIOS ENCONTRADOS: ' || V_CONTADOR);
        RETURN V_CONTADOR;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            DBMS_OUTPUT.PUT_LINE('NO SE ENCONTRARON USUARIOS CON: ' || P_NOMBRE_BUSCAR);
            RETURN 0;
        WHEN TOO_MANY_ROWS THEN
            DBMS_OUTPUT.PUT_LINE('DATOS DUPLICADOS');
            RETURN -1;
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
            RETURN -1;
    END FIDE_BUSCAR_USUARIOS_NOMBRE_FN;
    
    -- 8. Función Cantidad De Usuarios Por Estado
    FUNCTION FIDE_USUARIOS_POR_ESTADO_FN RETURN NUMBER IS
        CURSOR CURSOR_ESTADOS IS
            SELECT E.NOMBRE AS NOMBRE_ESTADO,
                   COUNT(U.ID_USUARIO) AS CANTIDAD_USUARIOS
            FROM FIDE_ESTADO_TB E
            LEFT JOIN FIDE_USUARIO_TB U ON E.ID_ESTADO = U.ID_ESTADO
            WHERE E.NOMBRE IN ('ACTIVO', 'INACTIVO')
            GROUP BY E.NOMBRE
            ORDER BY E.NOMBRE;
        V_CONTADOR NUMBER := 0;
        V_TOTAL_ACTIVOS NUMBER := 0;
        V_TOTAL_INACTIVOS NUMBER := 0;
    BEGIN
        FOR ESTADO IN CURSOR_ESTADOS
        LOOP
            V_CONTADOR := V_CONTADOR + 1;
            
            IF ESTADO.NOMBRE_ESTADO = 'ACTIVO' THEN
                V_TOTAL_ACTIVOS := ESTADO.CANTIDAD_USUARIOS;
            ELSIF ESTADO.NOMBRE_ESTADO = 'INACTIVO' THEN
                V_TOTAL_INACTIVOS := ESTADO.CANTIDAD_USUARIOS;
            END IF;
            
            DBMS_OUTPUT.PUT_LINE(
                'ESTADO: ' || ESTADO.NOMBRE_ESTADO ||
                ' - CANTIDAD: ' || ESTADO.CANTIDAD_USUARIOS
            );
        END LOOP;
        
        DBMS_OUTPUT.PUT_LINE('TOTAL ACTIVOS: ' || V_TOTAL_ACTIVOS);
        DBMS_OUTPUT.PUT_LINE('TOTAL INACTIVOS: ' || V_TOTAL_INACTIVOS);
        DBMS_OUTPUT.PUT_LINE('TOTAL GENERAL: ' || (V_TOTAL_ACTIVOS + V_TOTAL_INACTIVOS));
        
        RETURN V_CONTADOR;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            DBMS_OUTPUT.PUT_LINE('NO SE ENCONTRARON ESTADOS');
            RETURN 0;
        WHEN TOO_MANY_ROWS THEN
            DBMS_OUTPUT.PUT_LINE('DATOS DUPLICADOS');
            RETURN -1;
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
            RETURN -1;
    END FIDE_USUARIOS_POR_ESTADO_FN;
    
    -- 9. Función Promedio De Montos De Ahorros
    FUNCTION FIDE_PROMEDIO_AHORROS_FN RETURN NUMBER IS
        CURSOR CURSOR_AHORROS IS
            SELECT SALDO_ACTUAL
            FROM FIDE_CUENTAS_AHORRO_TB
            WHERE ID_ESTADO = 1;
        V_SUMA NUMBER := 0;
        V_CONTADOR NUMBER := 0;
        V_PROMEDIO NUMBER := 0;
    BEGIN
        FOR AHORRO IN CURSOR_AHORROS
        LOOP
            V_SUMA := V_SUMA + NVL(AHORRO.SALDO_ACTUAL, 0);
            V_CONTADOR := V_CONTADOR + 1;
        END LOOP;
        
        IF V_CONTADOR > 0 THEN
            V_PROMEDIO := V_SUMA / V_CONTADOR;
            DBMS_OUTPUT.PUT_LINE('SUMA TOTAL AHORROS: ' || V_SUMA);
            DBMS_OUTPUT.PUT_LINE('CANTIDAD CUENTAS: ' || V_CONTADOR);
            DBMS_OUTPUT.PUT_LINE('PROMEDIO DE AHORROS: ' || V_PROMEDIO);
        ELSE
            DBMS_OUTPUT.PUT_LINE('NO HAY CUENTAS DE AHORRO ACTIVAS');
        END IF;
        
        RETURN V_PROMEDIO;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            DBMS_OUTPUT.PUT_LINE('NO SE ENCONTRARON AHORROS');
            RETURN 0;
        WHEN ZERO_DIVIDE THEN
            DBMS_OUTPUT.PUT_LINE('NO HAY DATOS PARA CALCULAR PROMEDIO');
            RETURN 0;
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
            RETURN -1;
    END FIDE_PROMEDIO_AHORROS_FN;
    
    -- 10. Función Usuarios Registrados En El Último Mes
    FUNCTION FIDE_USUARIOS_ULTIMO_MES_FN RETURN NUMBER IS
        CURSOR CURSOR_ULTIMO_MES IS
            SELECT U.NOMBRE,
                   U.APELLIDO_PATERNO,
                   U.APELLIDO_MATERNO,
                   D.FECHA_AFILIACION
            FROM FIDE_USUARIO_TB U
            JOIN FIDE_DATOS_ASOCIADOS_TB D 
            ON U.ID_DATOS_ASOCIADOS = D.ID_DATOS_ASOCIADOS
            WHERE D.FECHA_AFILIACION >= ADD_MONTHS(SYSDATE, -1)
            ORDER BY D.FECHA_AFILIACION DESC;
        V_CONTADOR NUMBER := 0;
    BEGIN
        FOR USUARIO IN CURSOR_ULTIMO_MES
        LOOP
            V_CONTADOR := V_CONTADOR + 1;
            DBMS_OUTPUT.PUT_LINE(
                'USUARIO: ' || USUARIO.NOMBRE || ' ' || 
                USUARIO.APELLIDO_PATERNO || ' ' || 
                NVL(USUARIO.APELLIDO_MATERNO, '') ||
                ' - FECHA: ' || TO_CHAR(USUARIO.FECHA_AFILIACION, 'DD/MM/YYYY')
            );
        END LOOP;
        
        DBMS_OUTPUT.PUT_LINE('TOTAL USUARIOS NUEVOS ÚLTIMO MES: ' || V_CONTADOR);
        RETURN V_CONTADOR;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            DBMS_OUTPUT.PUT_LINE('NO HAY USUARIOS NUEVOS EN EL ÚLTIMO MES');
            RETURN 0;
        WHEN TOO_MANY_ROWS THEN
            DBMS_OUTPUT.PUT_LINE('DATOS DUPLICADOS');
            RETURN -1;
        WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
            RETURN -1;
    END FIDE_USUARIOS_ULTIMO_MES_FN;

-- 11. Función Top 5 Usuarios Con Más transacciones

FUNCTION FIDE_TOP5_USUARIOS_TRANSACCIONES_FN
RETURN NUMBER
IS
CURSOR CURSOR_TOP IS
SELECT *
FROM (
    SELECT U.ID_USUARIO,
           U.NOMBRE,
           U.APELLIDO_PATERNO,
           COUNT(T.ID_TRANSACCION) TOTAL_TRANSACCIONES
    FROM FIDE_USUARIO_TB U
    JOIN FIDE_TRANSACCION_TB T
    ON U.ID_USUARIO = T.ID_USUARIO
    GROUP BY U.ID_USUARIO, U.NOMBRE, U.APELLIDO_PATERNO
    ORDER BY TOTAL_TRANSACCIONES DESC
)
WHERE ROWNUM <= 5;

V_CONTADOR NUMBER := 0;

BEGIN
FOR USUARIO IN CURSOR_TOP
LOOP

V_CONTADOR := V_CONTADOR + 1;

DBMS_OUTPUT.PUT_LINE(
'USUARIO: ' || USUARIO.NOMBRE || ' ' || USUARIO.APELLIDO_PATERNO ||
' - TRANSACCIONES: ' || USUARIO.TOTAL_TRANSACCIONES);

END LOOP;

RETURN V_CONTADOR;

EXCEPTION
WHEN NO_DATA_FOUND THEN
DBMS_OUTPUT.PUT_LINE('NO SE ENCONTRARON DATOS');
RETURN 0;
WHEN TOO_MANY_ROWS THEN
DBMS_OUTPUT.PUT_LINE('DATOS DUPLICADOS');
RETURN -1;
WHEN OTHERS THEN
DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
RETURN -1;

END;
    
    
    -- 12. Función Cantidad transacciones por Usuario
    
    FUNCTION FIDE_CANTIDAD_TRANSACCIONES_USUARIO_FN(
P_ID_USUARIO NUMBER
)
RETURN NUMBER
IS
CURSOR CURSOR_TRANSACCIONES IS
SELECT *
FROM FIDE_TRANSACCION_TB
WHERE ID_USUARIO = P_ID_USUARIO;

V_CONTADOR NUMBER := 0;

BEGIN
FOR TRANS IN CURSOR_TRANSACCIONES
LOOP
V_CONTADOR := V_CONTADOR + 1;
END LOOP;

RETURN V_CONTADOR;

EXCEPTION

WHEN NO_DATA_FOUND THEN
DBMS_OUTPUT.PUT_LINE('USUARIO NO ENCONTRADO');
RETURN 0;
WHEN TOO_MANY_ROWS THEN
DBMS_OUTPUT.PUT_LINE('ERROR DE DATOS');
RETURN -1;
WHEN OTHERS THEN
DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
RETURN -1;

END;
    
     -- 13. Función Usuarios con mayores ahorros
     
     FUNCTION FIDE_USUARIOS_MAYOR_AHORRO_FN(
P_MONTO NUMBER
)
RETURN NUMBER
IS
CURSOR CURSOR_AHORRO IS
SELECT U.NOMBRE,
       U.APELLIDO_PATERNO,
       A.SALDO_ACTUAL
FROM FIDE_USUARIO_TB U
JOIN FIDE_CUENTAS_AHORRO_TB A
ON U.ID_USUARIO = A.ID_USUARIO
WHERE A.SALDO_ACTUAL > P_MONTO;

V_CONTADOR NUMBER := 0;

BEGIN
FOR USUARIO IN CURSOR_AHORRO
LOOP

V_CONTADOR := V_CONTADOR + 1;

DBMS_OUTPUT.PUT_LINE(
USUARIO.NOMBRE || ' ' || USUARIO.APELLIDO_PATERNO ||
' - AHORRO: ' || USUARIO.SALDO_ACTUAL);

END LOOP;

RETURN V_CONTADOR;

EXCEPTION

WHEN NO_DATA_FOUND THEN
DBMS_OUTPUT.PUT_LINE('NO HAY RESULTADOS');
RETURN 0;
WHEN TOO_MANY_ROWS THEN
DBMS_OUTPUT.PUT_LINE('ERROR EN DATOS');
RETURN -1;
WHEN OTHERS THEN
DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
RETURN -1;

END;
    
    
         -- 14. Función Historial de transacciones

FUNCTION FIDE_HISTORIAL_TRANSACCIONES_FN(
P_ID_USUARIO NUMBER
)
RETURN NUMBER
IS
CURSOR CURSOR_HISTORIAL IS
SELECT *
FROM FIDE_TRANSACCION_TB
WHERE ID_USUARIO = P_ID_USUARIO
ORDER BY FECHA_TRANSACCION;

V_CONTADOR NUMBER := 0;

BEGIN

FOR TRANS IN CURSOR_HISTORIAL
LOOP

V_CONTADOR := V_CONTADOR + 1;

DBMS_OUTPUT.PUT_LINE(
'TRANSACCION: ' || TRANS.ID_TRANSACCION ||
' - FECHA: ' || TRANS.FECHA_TRANSACCION ||
' - MONTO: ' || TRANS.MONTO_TOTAL);

END LOOP;

RETURN V_CONTADOR;

EXCEPTION
WHEN NO_DATA_FOUND THEN
DBMS_OUTPUT.PUT_LINE('NO HAY TRANSACCIONES');
RETURN 0;
WHEN TOO_MANY_ROWS THEN
DBMS_OUTPUT.PUT_LINE('ERROR EN DATOS');
RETURN -1;
WHEN OTHERS THEN
DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
RETURN -1;

END;

