CREATE OR REPLACE FUNCTION FIDE_TOP5_USUARIOS_TRANSACCIONES_FN
RETURN NUMBER
IS
CURSOR CURSOR_TOP IS
SELECT *
FROM (
    SELECT U.ID_USUARIO,
           U.NOMBRE,
           U.APELLIDO_PATERNO,
           COUNT(T.ID_TRANSACCION) TOTAL_TRANSACCIONES
    FROM FIDE_USUARIO_TB U
    JOIN FIDE_TRANSACCION_TB T
    ON U.ID_USUARIO = T.ID_USUARIO
    GROUP BY U.ID_USUARIO, U.NOMBRE, U.APELLIDO_PATERNO
    ORDER BY TOTAL_TRANSACCIONES DESC
)
WHERE ROWNUM <= 5;

V_CONTADOR NUMBER := 0;

BEGIN
FOR USUARIO IN CURSOR_TOP
LOOP

V_CONTADOR := V_CONTADOR + 1;

DBMS_OUTPUT.PUT_LINE(
'USUARIO: ' || USUARIO.NOMBRE || ' ' || USUARIO.APELLIDO_PATERNO ||
' - TRANSACCIONES: ' || USUARIO.TOTAL_TRANSACCIONES);

END LOOP;

RETURN V_CONTADOR;

EXCEPTION
WHEN NO_DATA_FOUND THEN
DBMS_OUTPUT.PUT_LINE('NO SE ENCONTRARON DATOS');
RETURN 0;
WHEN TOO_MANY_ROWS THEN
DBMS_OUTPUT.PUT_LINE('DATOS DUPLICADOS');
RETURN -1;
WHEN OTHERS THEN
DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
RETURN -1;

END;
/





SET SERVEROUTPUT ON;
CREATE OR REPLACE FUNCTION FIDE_CANTIDAD_TRANSACCIONES_USUARIO_FN(
P_ID_USUARIO NUMBER
)
RETURN NUMBER
IS
CURSOR CURSOR_TRANSACCIONES IS
SELECT *
FROM FIDE_TRANSACCION_TB
WHERE ID_USUARIO = P_ID_USUARIO;

V_CONTADOR NUMBER := 0;

BEGIN
FOR TRANS IN CURSOR_TRANSACCIONES
LOOP
V_CONTADOR := V_CONTADOR + 1;
END LOOP;

RETURN V_CONTADOR;

EXCEPTION

WHEN NO_DATA_FOUND THEN
DBMS_OUTPUT.PUT_LINE('USUARIO NO ENCONTRADO');
RETURN 0;
WHEN TOO_MANY_ROWS THEN
DBMS_OUTPUT.PUT_LINE('ERROR DE DATOS');
RETURN -1;
WHEN OTHERS THEN
DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
RETURN -1;

END;
/



SET SERVEROUTPUT ON;
CREATE OR REPLACE FUNCTION FIDE_USUARIOS_MAYOR_AHORRO_FN(
P_MONTO NUMBER
)
RETURN NUMBER
IS
CURSOR CURSOR_AHORRO IS
SELECT U.NOMBRE,
       U.APELLIDO_PATERNO,
       A.SALDO_ACTUAL
FROM FIDE_USUARIO_TB U
JOIN FIDE_CUENTAS_AHORRO_TB A
ON U.ID_USUARIO = A.ID_USUARIO
WHERE A.SALDO_ACTUAL > P_MONTO;

V_CONTADOR NUMBER := 0;

BEGIN
FOR USUARIO IN CURSOR_AHORRO
LOOP

V_CONTADOR := V_CONTADOR + 1;

DBMS_OUTPUT.PUT_LINE(
USUARIO.NOMBRE || ' ' || USUARIO.APELLIDO_PATERNO ||
' - AHORRO: ' || USUARIO.SALDO_ACTUAL);

END LOOP;

RETURN V_CONTADOR;

EXCEPTION

WHEN NO_DATA_FOUND THEN
DBMS_OUTPUT.PUT_LINE('NO HAY RESULTADOS');
RETURN 0;
WHEN TOO_MANY_ROWS THEN
DBMS_OUTPUT.PUT_LINE('ERROR EN DATOS');
RETURN -1;
WHEN OTHERS THEN
DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
RETURN -1;

END;
/



SET SERVEROUTPUT ON;
CREATE OR REPLACE FUNCTION FIDE_HISTORIAL_TRANSACCIONES_FN(
P_ID_USUARIO NUMBER
)
RETURN NUMBER
IS
CURSOR CURSOR_HISTORIAL IS
SELECT *
FROM FIDE_TRANSACCION_TB
WHERE ID_USUARIO = P_ID_USUARIO
ORDER BY FECHA_TRANSACCION;

V_CONTADOR NUMBER := 0;

BEGIN

FOR TRANS IN CURSOR_HISTORIAL
LOOP

V_CONTADOR := V_CONTADOR + 1;

DBMS_OUTPUT.PUT_LINE(
'TRANSACCION: ' || TRANS.ID_TRANSACCION ||
' - FECHA: ' || TRANS.FECHA_TRANSACCION ||
' - MONTO: ' || TRANS.MONTO_TOTAL);

END LOOP;

RETURN V_CONTADOR;

EXCEPTION
WHEN NO_DATA_FOUND THEN
DBMS_OUTPUT.PUT_LINE('NO HAY TRANSACCIONES');
RETURN 0;
WHEN TOO_MANY_ROWS THEN
DBMS_OUTPUT.PUT_LINE('ERROR EN DATOS');
RETURN -1;
WHEN OTHERS THEN
DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
RETURN -1;

END;
/




SET SERVEROUTPUT ON;
CREATE OR REPLACE FUNCTION FIDE_REPORTE_AHORROS_USUARIO_FN(
P_ID_USUARIO NUMBER
)
RETURN NUMBER
IS
CURSOR CURSOR_REPORTE IS
SELECT *
FROM FIDE_CUENTAS_AHORRO_TB
WHERE ID_USUARIO = P_ID_USUARIO;

V_CONTADOR NUMBER := 0;

BEGIN
FOR AHORRO IN CURSOR_REPORTE
LOOP

V_CONTADOR := V_CONTADOR + 1;

DBMS_OUTPUT.PUT_LINE(
'CUENTA: ' || AHORRO.ID_AHORRO ||
' - MONTO APORTE: ' || AHORRO.MONTO_APORTE ||
' - SALDO ACTUAL: ' || AHORRO.SALDO_ACTUAL);

END LOOP;

RETURN V_CONTADOR;

EXCEPTION
WHEN NO_DATA_FOUND THEN
DBMS_OUTPUT.PUT_LINE('NO EXISTEN AHORROS');
RETURN 0;
WHEN TOO_MANY_ROWS THEN
DBMS_OUTPUT.PUT_LINE('ERROR EN DATOS');
RETURN -1;
WHEN OTHERS THEN
DBMS_OUTPUT.PUT_LINE('ERROR: ' || SQLERRM);
RETURN -1;

END;
/


--------------------------------------------------------------------------------------
--------------------------------- VISTAS --------------------------------
--------------------------------------------------------------------------------------

-- 1. Vista Usuarios Roles
CREATE OR REPLACE VIEW V_FIDE_USUARIOS_ROLES AS
SELECT U.ID_USUARIO,
       U.NOMBRE || ' ' || U.APELLIDO_PATERNO || ' ' || U.APELLIDO_MATERNO AS NOMBRE_COMPLETO,
       U.NOMBRE_USUARIO,
       R.NOMBRE_ROL,
       C.CORREO_ELECTRONICO,
       E.NOMBRE AS ESTADO_USUARIO
FROM FIDE_USUARIO_TB U
JOIN FIDE_ROL_TB R ON U.ID_ROL = R.ID_ROL
LEFT JOIN FIDE_CORREO_ELECTRONICO_TB C ON U.ID_CORREO = C.ID_CORREO
JOIN FIDE_ESTADO_TB E ON U.ID_ESTADO = E.ID_ESTADO;
/
SELECT * FROM V_FIDE_USUARIOS_ROLES;
/

-- 2. Vista Estado Préstamos
CREATE OR REPLACE VIEW V_FIDE_ESTADO_PRESTAMOS AS
SELECT P.ID_PRESTAMO,
       U.NOMBRE || ' ' || U.APELLIDO_PATERNO AS CLIENTE,
       P.MONTO_SOLICITADO,
       P.SALDO_PENDIENTE,
       P.TASA_INTERESES,
       P.PLAZO_MESES,
       P.FECHA_APROBACION,
       E.NOMBRE AS ESTADO_PRESTAMO
FROM FIDE_PRESTAMO_TB P
JOIN FIDE_USUARIO_TB U ON P.ID_USUARIO = U.ID_USUARIO
JOIN FIDE_ESTADO_TB E ON P.ID_ESTADO = E.ID_ESTADO;
/
SELECT * FROM V_FIDE_ESTADO_PRESTAMOS;
/

-- 3. Vista Resumen Ahorros
CREATE OR REPLACE VIEW V_FIDE_RESUMEN_AHORROS AS
SELECT A.ID_AHORRO,
       U.NOMBRE_USUARIO,
       TA.NOMBRE AS TIPO_AHORRO,
       A.MONTO_APORTE,
       A.SALDO_ACTUAL,
       A.FECHA_APERTURA,
       E.NOMBRE AS ESTADO_CUENTA
FROM FIDE_CUENTAS_AHORRO_TB A
JOIN FIDE_USUARIO_TB U ON A.ID_USUARIO = U.ID_USUARIO
JOIN FIDE_TIPO_AHORRO_TB TA ON A.ID_TIPO_AHORRO = TA.ID_TIPO_AHORRO
JOIN FIDE_ESTADO_TB E ON A.ID_ESTADO = E.ID_ESTADO;
/
SELECT * FROM V_FIDE_RESUMEN_AHORROS;
/

-- 4. Vista Actividades Programadas
CREATE OR REPLACE VIEW V_FIDE_ACTIVIDADES_PROGRAMADAS AS
SELECT AC.ID_ACTIVIDAD,
       AC.NOMBRE AS NOMBRE_ACTIVIDAD,
       AC.FECHA_EVENTO,
       AC.LUGAR,
       AC.CUPO_TOTAL,
       E.NOMBRE AS ESTADO_ACTIVIDAD
FROM FIDE_ACTIVIDAD_TB AC
JOIN FIDE_ESTADO_TB E ON AC.ID_ESTADO = E.ID_ESTADO;
/
SELECT * FROM V_FIDE_ACTIVIDADES_PROGRAMADAS;
/

--5. Vista materializada Top usuarios con más transacciones

CREATE MATERIALIZED VIEW FIDE_TOP_USUARIOS_TRANSACCIONES_VM
REFRESH COMPLETE ON DEMAND AS
SELECT *
FROM (
    SELECT U.ID_USUARIO,
           U.NOMBRE,
           U.APELLIDO_PATERNO,
           COUNT(T.ID_TRANSACCION) AS TOTAL_TRANSACCIONES
    FROM FIDE_USUARIO_TB U,
         FIDE_TRANSACCION_TB T
    WHERE U.ID_USUARIO = T.ID_USUARIO
    GROUP BY U.ID_USUARIO, U.NOMBRE, U.APELLIDO_PATERNO
    ORDER BY TOTAL_TRANSACCIONES DESC
)
WHERE ROWNUM <= 5;
/

--6. Vista materializada Usuarios con mayor ahorro

CREATE MATERIALIZED VIEW FIDE_USUARIOS_MAYOR_AHORRO_VM
REFRESH COMPLETE ON DEMAND AS
SELECT U.ID_USUARIO,
       U.NOMBRE,
       U.APELLIDO_PATERNO,
       A.SALDO_ACTUAL
FROM FIDE_USUARIO_TB U,
     FIDE_CUENTAS_AHORRO_TB A
WHERE U.ID_USUARIO = A.ID_USUARIO
ORDER BY A.SALDO_ACTUAL DESC;
/


--7. Vista materializada Historial de transacciones

CREATE MATERIALIZED VIEW FIDE_HISTORIAL_TRANSACCIONES_VM
REFRESH COMPLETE ON DEMAND AS
SELECT T.ID_TRANSACCION,
       T.FECHA_TRANSACCION,
       T.MONTO_TOTAL,
       U.ID_USUARIO,
       U.NOMBRE,
       U.APELLIDO_PATERNO
FROM FIDE_TRANSACCION_TB T,
     FIDE_USUARIO_TB U
WHERE T.ID_USUARIO = U.ID_USUARIO
ORDER BY T.FECHA_TRANSACCION DESC;
/


-- 8. VISTA NORMAL
CREATE OR REPLACE VIEW V_FIDE_USUARIOS_COMPLETOS AS
SELECT U.ID_USUARIO,
       U.IDENTIFICACION,
       U.NOMBRE,
       U.APELLIDO_PATERNO,
       U.APELLIDO_MATERNO,
       U.NOMBRE_USUARIO,
       C.CORREO_ELECTRONICO,
       N.NUMERO_TELEFONO,
       E.NOMBRE AS ESTADO_USUARIO,
       D.FECHA_AFILIACION
FROM FIDE_USUARIO_TB U
LEFT JOIN FIDE_CORREO_ELECTRONICO_TB C ON U.ID_CORREO = C.ID_CORREO
LEFT JOIN FIDE_NUMERO_TELEFONO_TB N ON U.ID_NUMERO = N.ID_NUMERO
JOIN FIDE_ESTADO_TB E ON U.ID_ESTADO = E.ID_ESTADO
LEFT JOIN FIDE_DATOS_ASOCIADOS_TB D ON U.ID_DATOS_ASOCIADOS = D.ID_DATOS_ASOCIADOS;
/

SELECT * FROM V_FIDE_USUARIOS_COMPLETOS;
/

-- 9. VISTA MATERIALIZADA: Top 10 usuarios con menos ahorros
CREATE MATERIALIZED VIEW FIDE_TOP10_MENOS_AHORROS_VM
REFRESH COMPLETE ON DEMAND AS
SELECT *
FROM (
    SELECT U.ID_USUARIO,
           U.NOMBRE,
           U.APELLIDO_PATERNO,
           NVL(SUM(A.SALDO_ACTUAL), 0) AS TOTAL_AHORRO
    FROM FIDE_USUARIO_TB U
    LEFT JOIN FIDE_CUENTAS_AHORRO_TB A ON U.ID_USUARIO = A.ID_USUARIO
    GROUP BY U.ID_USUARIO, U.NOMBRE, U.APELLIDO_PATERNO
    ORDER BY TOTAL_AHORRO ASC
)
WHERE ROWNUM <= 10;
/


-- 10. VISTA MATERIALIZADA Usuarios registrados en el último mes
CREATE MATERIALIZED VIEW FIDE_USUARIOS_ULTIMO_MES_VM
REFRESH COMPLETE ON DEMAND AS
SELECT U.ID_USUARIO,
       U.NOMBRE,
       U.APELLIDO_PATERNO,
       U.APELLIDO_MATERNO,
       U.NOMBRE_USUARIO,
       D.FECHA_AFILIACION
FROM FIDE_USUARIO_TB U
JOIN FIDE_DATOS_ASOCIADOS_TB D ON U.ID_DATOS_ASOCIADOS = D.ID_DATOS_ASOCIADOS
WHERE D.FECHA_AFILIACION >= ADD_MONTHS(SYSDATE, -1)
ORDER BY D.FECHA_AFILIACION DESC;
/

-- 11. Vista Aportes por Usuario
CREATE OR REPLACE VIEW V_FIDE_APORTES_USUARIO AS
SELECT U.ID_USUARIO,
       U.NOMBRE || ' ' || U.APELLIDO_PATERNO || ' ' || U.APELLIDO_MATERNO AS NOMBRE_COMPLETO,
       U.NOMBRE_USUARIO,
       DA.APORTE_MENSUAL,
       DA.FECHA_AFILIACION,
       E.NOMBRE AS ESTADO_USUARIO
FROM FIDE_USUARIO_TB U
JOIN FIDE_DATOS_ASOCIADOS_TB DA ON U.ID_DATOS_ASOCIADOS = DA.ID_DATOS_ASOCIADOS
JOIN FIDE_ESTADO_TB E ON U.ID_ESTADO = E.ID_ESTADO;
/


-- 12. Vista Ahorros del Usuario
CREATE OR REPLACE VIEW V_FIDE_AHORROS_USUARIO AS
SELECT 
    U.ID_USUARIO,
    
    U.NOMBRE || ' ' || U.APELLIDO_PATERNO || ' ' || U.APELLIDO_MATERNO 
        AS NOMBRE_COMPLETO,
        
    U.NOMBRE_USUARIO,
    
    CA.ID_AHORRO,
    CA.FECHA_APERTURA,
    CA.MONTO_APORTE,
    CA.SALDO_ACTUAL,
    
    TA.NOMBRE AS TIPO_AHORRO,
    
    E.NOMBRE AS ESTADO_CUENTA

FROM FIDE_USUARIO_TB U
JOIN FIDE_CUENTAS_AHORRO_TB CA ON U.ID_USUARIO = CA.ID_USUARIO
JOIN FIDE_TIPO_AHORRO_TB TA ON CA.ID_TIPO_AHORRO = TA.ID_TIPO_AHORRO
JOIN FIDE_ESTADO_TB E ON CA.ID_ESTADO = E.ID_ESTADO;
/


-- 13. Vista Préstamos con detalle completo
CREATE OR REPLACE VIEW V_FIDE_PRESTAMOS_DETALLE AS
SELECT 
    U.NOMBRE || ' ' || U.APELLIDO_PATERNO || ' ' || NVL(U.APELLIDO_MATERNO, '') AS NOMBRE_ASOCIADO,
    P.MONTO_SOLICITADO,
    P.SALDO_PENDIENTE,
    (SELECT COUNT(PP.ID_PAGO) FROM FIDE_PAGOS_PRESTAMOS_TB PP WHERE PP.ID_PRESTAMO = P.ID_PRESTAMO) AS CUOTAS_PAGADAS,
    (P.PLAZO_MESES - (SELECT COUNT(PP.ID_PAGO) FROM FIDE_PAGOS_PRESTAMOS_TB PP WHERE PP.ID_PRESTAMO = P.ID_PRESTAMO)) AS CUOTAS_PENDIENTES,
    ADD_MONTHS(P.FECHA_APROBACION, P.PLAZO_MESES) AS FECHA_VENCIMIENTO,
    P.TASA_INTERESES AS TASA_INTERES,
    E.NOMBRE AS ESTADO
FROM FIDE_PRESTAMO_TB P
JOIN FIDE_USUARIO_TB U ON P.ID_USUARIO = U.ID_USUARIO
JOIN FIDE_ESTADO_TB E ON P.ID_ESTADO = E.ID_ESTADO;
/


-- 14. Vista Transacciones recientes
CREATE OR REPLACE VIEW V_FIDE_TRANSACCIONES_RECIENTES AS
SELECT * FROM (
    SELECT 
        U.NOMBRE_USUARIO,
        TT.NOMBRE AS TIPO_TRANSACCION,
        T.MONTO_TOTAL AS MONTO,
        T.FECHA_TRANSACCION,
        DT.CONCEPTO AS DESCRIPCION
    FROM FIDE_TRANSACCION_TB T
    JOIN FIDE_USUARIO_TB U ON T.ID_USUARIO = U.ID_USUARIO
    JOIN FIDE_TIPO_TRANSACCION_TB TT ON T.ID_TIPO_TRANSACCION = TT.ID_TIPO_TRANSACCION
    LEFT JOIN FIDE_DETALLE_TRANSACCION_TB DT ON T.ID_TRANSACCION = DT.ID_TRANSACCION
    ORDER BY T.FECHA_TRANSACCION DESC
)
WHERE ROWNUM <= 20;
/


-- 15. Vista Asociados nuevos este mes
CREATE OR REPLACE VIEW V_FIDE_ASOCIADOS_NUEVOS_MES AS
SELECT 
    U.NOMBRE || ' ' || U.APELLIDO_PATERNO || ' ' || NVL(U.APELLIDO_MATERNO, '') AS NOMBRE_COMPLETO,
    C.CORREO_ELECTRONICO AS CORREO,
    DA.FECHA_AFILIACION,
    E.NOMBRE AS ESTADO,
    DA.APORTE_MENSUAL
FROM FIDE_USUARIO_TB U
JOIN FIDE_DATOS_ASOCIADOS_TB DA ON U.ID_DATOS_ASOCIADOS = DA.ID_DATOS_ASOCIADOS
LEFT JOIN FIDE_CORREO_ELECTRONICO_TB C ON U.ID_CORREO = C.ID_CORREO
JOIN FIDE_ESTADO_TB E ON U.ID_ESTADO = E.ID_ESTADO
WHERE TO_CHAR(DA.FECHA_AFILIACION, 'YYYY-MM') = TO_CHAR(SYSDATE, 'YYYY-MM');
/


-- 16. Vista Servicios más solicitados
CREATE OR REPLACE VIEW V_FIDE_SERVICIOS_MAS_SOLICITADOS AS
SELECT 
    S.NOMBRE_SERVICIO,
    0 AS TOTAL_SOLICITUDES,
    S.STOCK AS STOCK_DISPONIBLE,
    S.VALOR_ESTIMADO
FROM FIDE_SERVICIO_TB S
ORDER BY S.STOCK ASC;
/


-- 17. Vista Actividades con sus inscritos
CREATE OR REPLACE VIEW V_FIDE_ACTIVIDADES_CON_INSCRITOS AS
SELECT 
    A.NOMBRE AS NOMBRE_ACTIVIDAD,
    A.FECHA_EVENTO,
    A.LUGAR,
    COUNT(I.ID_INSCRIPCION) AS TOTAL_INSCRITOS,
    (A.CUPO_TOTAL - COUNT(I.ID_INSCRIPCION)) AS CUPO_DISPONIBLE
FROM FIDE_ACTIVIDAD_TB A
LEFT JOIN FIDE_INSCRIPCIONES_ACTIVIDAD_TB I ON A.ID_ACTIVIDAD = I.ID_ACTIVIDAD
GROUP BY A.ID_ACTIVIDAD, A.NOMBRE, A.FECHA_EVENTO, A.LUGAR, A.CUPO_TOTAL;
/


-- 18. Vista Top 10 asociados con más ahorros
CREATE OR REPLACE VIEW V_FIDE_TOP10_MAS_AHORROS AS
SELECT * FROM (
    SELECT 
        U.NOMBRE || ' ' || U.APELLIDO_PATERNO || ' ' || NVL(U.APELLIDO_MATERNO, '') AS NOMBRE_COMPLETO,
        SUM(A.SALDO_ACTUAL) AS TOTAL_AHORRO,
        COUNT(A.ID_AHORRO) AS CANTIDAD_CUENTAS
    FROM FIDE_USUARIO_TB U
    JOIN FIDE_CUENTAS_AHORRO_TB A ON U.ID_USUARIO = A.ID_USUARIO
    GROUP BY U.ID_USUARIO, U.NOMBRE, U.APELLIDO_PATERNO, U.APELLIDO_MATERNO
    ORDER BY TOTAL_AHORRO DESC
)
WHERE ROWNUM <= 10;
/


-- 19. Vista Top 5 usuarios con más transacciones
CREATE OR REPLACE VIEW V_FIDE_TOP5_TRANSACCIONES AS
SELECT * FROM (
    SELECT 
        U.NOMBRE || ' ' || U.APELLIDO_PATERNO || ' ' || NVL(U.APELLIDO_MATERNO, '') AS NOMBRE_COMPLETO,
        COUNT(T.ID_TRANSACCION) AS TOTAL_TRANSACCIONES,
        SUM(T.MONTO_TOTAL) AS MONTO_TOTAL
    FROM FIDE_USUARIO_TB U
    JOIN FIDE_TRANSACCION_TB T ON U.ID_USUARIO = T.ID_USUARIO
    GROUP BY U.ID_USUARIO, U.NOMBRE, U.APELLIDO_PATERNO, U.APELLIDO_MATERNO
    ORDER BY TOTAL_TRANSACCIONES DESC
)
WHERE ROWNUM <= 5;
/


-- 20. Vista Usuarios registrados último mes
CREATE OR REPLACE VIEW V_FIDE_USUARIOS_ULTIMO_MES AS
SELECT 
    U.NOMBRE || ' ' || U.APELLIDO_PATERNO || ' ' || NVL(U.APELLIDO_MATERNO, '') AS NOMBRE_COMPLETO,
    DA.FECHA_AFILIACION,
    C.CORREO_ELECTRONICO AS CORREO,
    E.NOMBRE AS ESTADO
FROM FIDE_USUARIO_TB U
JOIN FIDE_DATOS_ASOCIADOS_TB DA ON U.ID_DATOS_ASOCIADOS = DA.ID_DATOS_ASOCIADOS
LEFT JOIN FIDE_CORREO_ELECTRONICO_TB C ON U.ID_CORREO = C.ID_CORREO
JOIN FIDE_ESTADO_TB E ON U.ID_ESTADO = E.ID_ESTADO
WHERE DA.FECHA_AFILIACION >= ADD_MONTHS(SYSDATE, -1);
/


-- 21. Vista Resumen de estados del sistema
CREATE OR REPLACE VIEW V_FIDE_RESUMEN_ESTADOS AS
SELECT 
    E.NOMBRE AS ESTADO,
    (SELECT COUNT(U.ID_USUARIO) FROM FIDE_USUARIO_TB U WHERE U.ID_ESTADO = E.ID_ESTADO) AS TOTAL_USUARIOS,
    (SELECT COUNT(P.ID_PRESTAMO) FROM FIDE_PRESTAMO_TB P WHERE P.ID_ESTADO = E.ID_ESTADO) AS TOTAL_PRESTAMOS,
    (SELECT COUNT(A.ID_AHORRO) FROM FIDE_CUENTAS_AHORRO_TB A WHERE A.ID_ESTADO = E.ID_ESTADO) AS TOTAL_CUENTAS_AHORRO,
    (SELECT COUNT(AC.ID_ACTIVIDAD) FROM FIDE_ACTIVIDAD_TB AC WHERE AC.ID_ESTADO = E.ID_ESTADO) AS TOTAL_ACTIVIDADES
FROM FIDE_ESTADO_TB E;
/


-- 22. Vista Cuentas ahorro por tipo y estado
CREATE OR REPLACE VIEW V_FIDE_AHORROS_POR_TIPO_ESTADO AS
SELECT 
    TA.NOMBRE AS TIPO_AHORRO,
    E.NOMBRE AS ESTADO,
    COUNT(A.ID_AHORRO) AS CANTIDAD_CUENTAS,
    SUM(A.SALDO_ACTUAL) AS SALDO_TOTAL,
    (SUM(A.SALDO_ACTUAL) / NULLIF(COUNT(A.ID_AHORRO), 0)) AS PROMEDIO_SALDO
FROM FIDE_CUENTAS_AHORRO_TB A
JOIN FIDE_TIPO_AHORRO_TB TA ON A.ID_TIPO_AHORRO = TA.ID_TIPO_AHORRO
JOIN FIDE_ESTADO_TB E ON A.ID_ESTADO = E.ID_ESTADO
GROUP BY TA.NOMBRE, E.NOMBRE;
/


-- 23. Vista Mis préstamos
CREATE OR REPLACE VIEW V_FIDE_MIS_PRESTAMOS AS
SELECT 
    U.NOMBRE_USUARIO,
    P.MONTO_SOLICITADO,
    P.SALDO_PENDIENTE,
    (SELECT COUNT(PP.ID_PAGO) FROM FIDE_PAGOS_PRESTAMOS_TB PP WHERE PP.ID_PRESTAMO = P.ID_PRESTAMO) AS CUOTAS_PAGADAS,
    (P.PLAZO_MESES - (SELECT COUNT(PP.ID_PAGO) FROM FIDE_PAGOS_PRESTAMOS_TB PP WHERE PP.ID_PRESTAMO = P.ID_PRESTAMO)) AS CUOTAS_PENDIENTES,
    ADD_MONTHS(P.FECHA_APROBACION, (SELECT COUNT(PP.ID_PAGO) FROM FIDE_PAGOS_PRESTAMOS_TB PP WHERE PP.ID_PRESTAMO = P.ID_PRESTAMO) + 1) AS PROXIMA_FECHA_PAGO,
    E.NOMBRE AS ESTADO
FROM FIDE_PRESTAMO_TB P
JOIN FIDE_USUARIO_TB U ON P.ID_USUARIO = U.ID_USUARIO
JOIN FIDE_ESTADO_TB E ON P.ID_ESTADO = E.ID_ESTADO;
/


-- 24. Vista Mis transacciones recientes
CREATE OR REPLACE VIEW V_FIDE_MIS_TRANSACCIONES AS
SELECT 
    U.NOMBRE_USUARIO,
    TT.NOMBRE AS TIPO_TRANSACCION,
    T.MONTO_TOTAL AS MONTO,
    T.FECHA_TRANSACCION,
    DT.CONCEPTO AS DESCRIPCION
FROM FIDE_TRANSACCION_TB T
JOIN FIDE_USUARIO_TB U ON T.ID_USUARIO = U.ID_USUARIO
JOIN FIDE_TIPO_TRANSACCION_TB TT ON T.ID_TIPO_TRANSACCION = TT.ID_TIPO_TRANSACCION
LEFT JOIN FIDE_DETALLE_TRANSACCION_TB DT ON T.ID_TRANSACCION = DT.ID_TRANSACCION
ORDER BY T.FECHA_TRANSACCION DESC;
/


-- 25. Vista Mis inscripciones a actividades
CREATE OR REPLACE VIEW V_FIDE_MIS_INSCRIPCIONES AS
SELECT 
    U.NOMBRE_USUARIO,
    A.NOMBRE AS NOMBRE_ACTIVIDAD,
    A.FECHA_EVENTO,
    A.LUGAR,
    E.NOMBRE AS ESTADO_INSCRIPCION
FROM FIDE_INSCRIPCIONES_ACTIVIDAD_TB I
JOIN FIDE_USUARIO_TB U ON I.ID_USUARIO = U.ID_USUARIO
JOIN FIDE_ACTIVIDAD_TB A ON I.ID_ACTIVIDAD = A.ID_ACTIVIDAD
JOIN FIDE_ESTADO_TB E ON I.ID_ESTADO = E.ID_ESTADO;
/


-- 26. Vista Beneficios con detalle
CREATE OR REPLACE VIEW V_FIDE_BENEFICIOS_DETALLE AS
SELECT 
    B.NOMBRE_BENEFICIO,
    B.DESCRIPCION,
    C.NOMBRE AS CATEGORIA,
    E.NOMBRE AS VIGENCIA
FROM FIDE_BENEFICIO_TB B
JOIN FIDE_CATEGORIA_TB C ON B.ID_CATEGORIA = C.ID_CATEGORIA
JOIN FIDE_ESTADO_TB E ON B.ID_ESTADO = E.ID_ESTADO;
/


-- 27. Vista Historial de aportes del asociado
CREATE OR REPLACE VIEW V_FIDE_HISTORIAL_APORTES AS
SELECT 
    U.NOMBRE_USUARIO,
    TO_NUMBER(TO_CHAR(T.FECHA_TRANSACCION, 'MM')) AS MES,
    TO_NUMBER(TO_CHAR(T.FECHA_TRANSACCION, 'YYYY')) AS ANIO,
    DT.SUB_TOTAL AS MONTO_APORTE,
    E.NOMBRE AS ESTADO_PAGO
FROM FIDE_TRANSACCION_TB T
JOIN FIDE_USUARIO_TB U ON T.ID_USUARIO = U.ID_USUARIO
JOIN FIDE_ESTADO_TB E ON T.ID_ESTADO = E.ID_ESTADO
JOIN FIDE_DETALLE_TRANSACCION_TB DT ON T.ID_TRANSACCION = DT.ID_TRANSACCION
WHERE UPPER(DT.CONCEPTO) LIKE '%APORTE%';
/


