--ALTER PARA INCLUIR ATRIBUTOS DE AUDITORÍA-

ALTER TABLE FIDE_ESTADO_TB
ADD (FECHA_CREACION TIMESTAMP,
FECHA_MODIFICACION TIMESTAMP,
CREADO_POR VARCHAR2(100),
