   -- ACTUALIZACIÓN Función Ordenar Usuarios Alfabéticamente
    FUNCTION FIDE_ORDENAR_USUARIOS_ALFABETICO_FN 
RETURN SYS_REFCURSOR 
IS
    V_CURSOR SYS_REFCURSOR;
BEGIN
    OPEN V_CURSOR FOR
        SELECT 
            U.ID_USUARIO,
            U.NOMBRE || ' ' || U.APELLIDO_PATERNO || ' ' || U.APELLIDO_MATERNO AS NOMBRE_COMPLETO,
            U.NOMBRE_USUARIO,
            T.NUMERO_TELEFONO,
            C.CORREO_ELECTRONICO,
            D.DISTRITO,
            DA.APORTE_MENSUAL,
            E.NOMBRE AS ESTADO
        FROM FIDE_USUARIO_TB U
        LEFT JOIN FIDE_NUMERO_TELEFONO_TB T ON U.ID_NUMERO = T.ID_NUMERO
        LEFT JOIN FIDE_CORREO_ELECTRONICO_TB C ON U.ID_CORREO = C.ID_CORREO
        LEFT JOIN FIDE_DIRECCION_TB D ON U.ID_DIRECCION = D.ID_DIRECCION
        LEFT JOIN FIDE_DATOS_ASOCIADOS_TB DA ON U.ID_DATOS_ASOCIADOS = DA.ID_DATOS_ASOCIADOS
        LEFT JOIN FIDE_ESTADO_TB E ON U.ID_ESTADO = E.ID_ESTADO
        ORDER BY 
            U.NOMBRE ASC, 
            U.APELLIDO_PATERNO ASC, 
            U.APELLIDO_MATERNO ASC;

    RETURN V_CURSOR;

EXCEPTION
    WHEN OTHERS THEN
        RETURN NULL;
END FIDE_ORDENAR_USUARIOS_ALFABETICO_FN;


--SEQUENCIAS Y TRIGGERS PARA LOS REPORTES--

--SECUENCIA
CREATE SEQUENCE FIDE_REPORTES_SEQ
START WITH 1
INCREMENT BY 1;
/

--FUNCION NUMERICA DE REPORTES
CREATE OR REPLACE FUNCTION FIDE_REPORTE_NUM_FN
RETURN NUMBER AS
V_FECHA VARCHAR2(10);
V_VALOR NUMBER;
BEGIN
V_FECHA:=TO_CHAR(SYSDATE, 'DDMMYYYY');
V_VALOR:=TO_NUMBER(V_FECHA|| LPAD(FIDE_REPORTES_SEQ.NEXTVAL, 7, 0));
RETURN V_VALOR;
END;
/

--PARA PROBAR LA FUNCIÓN
SELECT FIDE_REPORTE_NUM_FN FROM DUAL;

SET SERVEROUTPUT ON;

