-- JOBS PARA VISTAS MATERIALIZADAS

-- JOB 1: Actualizar FIDE_TOP10_MENOS_AHORROS_VM cada 5 minutos
BEGIN
DBMS_SCHEDULER.CREATE_JOB(
JOB_NAME => 'FIDE_ASEFIDE_REFRESH_TOP10_MENOS_AHORROS_JOB',
JOB_TYPE => 'PLSQL_BLOCK',
JOB_ACTION => 'BEGIN DBMS_MVIEW.REFRESH(''FIDE_TOP10_MENOS_AHORROS_VM'',''C''); END;',
START_DATE => SYSTIMESTAMP,
REPEAT_INTERVAL => 'FREQ=MINUTELY; INTERVAL=5',
ENABLED => TRUE
);
END;
/

